"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"

export interface LemmaSchemaFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSubmit"> {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<void> | void
  onSubmitted?: (data: Record<string, unknown>) => void
  showReset?: boolean
  resetLabel?: string
  hiddenFields?: string[]
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
}

export const LemmaSchemaForm = React.forwardRef<HTMLDivElement, LemmaSchemaFormProps>(
  ({
    schema,
    uiSchema,
    initialValues,
    title = "Schema Form",
    description = "Generated from JSON Schema.",
    submitLabel = "Submit",
    disabled = false,
    onSubmit,
    onSubmitted,
    showReset = true,
    resetLabel = "Reset",
    hiddenFields = [],
    fieldLabels,
    fieldDescriptions,
    className,
    ...props
  }, ref) => {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent>
        <form className="grid gap-4" onSubmit={handleSubmit}>
          {form.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {form.error.message}
            </div>
          ) : null}

          {!hasFields ? (
            <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
              This schema does not define any editable fields.
            </div>
          ) : null}

          {form.fields
            .filter((field) => !hiddenFields.includes(field.name))
            .map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const resolvedLabel = fieldLabels?.[field.name] ?? field.label
            const resolvedDescription = fieldDescriptions?.[field.name] ?? field.description
            const commonLabel = (
              <div className="grid gap-1.5">
                <Label htmlFor={field.name}>
                  {resolvedLabel}
                  {field.required ? " *" : ""}
                </Label>
                {resolvedDescription ? (
                  <p className="text-sm text-muted-foreground">{resolvedDescription}</p>
                ) : null}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="grid gap-2 rounded-lg border border-border bg-muted/30 p-4">
                  {commonLabel}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span>{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Textarea
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {commonLabel}
                <Input
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex items-center gap-2 pt-2">
            <Button disabled={disabled || form.isSubmitting} type="submit">
              {form.isSubmitting ? "Submitting…" : submitLabel}
            </Button>
            {showReset ? (
              <Button
                disabled={disabled || form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
              >
                {resetLabel}
              </Button>
            ) : null}
          </div>
        </form>
      </CardContent>
    </Card>
  )
})
LemmaSchemaForm.displayName = "LemmaSchemaForm"

"use client"

import * as React from "react"
import type { JsonSchemaLike, LemmaClient, FunctionRun } from "lemma-sdk"
import { useFunctionRun } from "lemma-sdk/react"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"
import { cn } from "@/lib/utils"

export interface LemmaFunctionRunPanelProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  functionName: string
  inputSchema?: JsonSchemaLike | null
  title?: string
  description?: string
  onStarted?: (run: FunctionRun) => void
  onError?: (error: Error) => void
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaFunctionRunPanel = React.forwardRef<HTMLDivElement, LemmaFunctionRunPanelProps>(
  ({
    client,
    podId,
    functionName,
    inputSchema,
    title = "Function Runner",
    description = "Run a function and inspect status plus output.",
    onStarted,
    onError,
    className,
    ...props
  }, ref) => {
  const run = useFunctionRun({
    client,
    podId,
    functionName: functionName || undefined,
  })

  React.useEffect(() => {
    if (run.error) {
      onError?.(run.error)
    }
  }, [run.error, onError])

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <LemmaSchemaForm
        disabled={!functionName || run.isPolling}
        description={description}
        onSubmit={async (data) => {
          const created = await run.start(data)
          onStarted?.(created)
        }}
        schema={inputSchema}
        submitLabel={run.isPolling ? "Running..." : "Run function"}
        title={title}
      />
      <Card>
        <CardHeader>
          <CardTitle>Function Run</CardTitle>
          <CardDescription>Latest run status and output.</CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          {run.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {run.error.message}
            </div>
          ) : null}
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="rounded-md border border-border bg-muted/30 p-4 text-sm">
              <div className="text-muted-foreground">Status</div>
              <div className="font-medium">{run.status ?? "idle"}</div>
            </div>
            <div className="rounded-md border border-border bg-muted/30 p-4 text-sm">
              <div className="text-muted-foreground">Run ID</div>
              <div className="truncate font-medium">{run.runId ?? "none"}</div>
            </div>
          </div>
          {run.output ? (
            <pre className="max-h-[360px] overflow-auto rounded-md border border-border bg-muted/40 p-4 text-sm leading-6">
              {formatJson(run.output)}
            </pre>
          ) : (
            <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
              Run the function to inspect output.
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  )
})
LemmaFunctionRunPanel.displayName = "LemmaFunctionRunPanel"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useFunctionRuns } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { cn } from "@/lib/utils"

export interface LemmaFunctionRunHistoryProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  functionName: string
  title?: string
  description?: string
  onRunSelect?: (runId: string | null) => void
}

export const LemmaFunctionRunHistory = React.forwardRef<HTMLDivElement, LemmaFunctionRunHistoryProps>(
  ({
    client,
    podId,
    functionName,
    title = "Function Run History",
    description = "Recent runs for the selected function.",
    onRunSelect,
    className,
    ...props
  }, ref) => {
  const history = useFunctionRuns({
    client,
    podId,
    functionName,
    enabled: functionName.trim().length > 0,
  })

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={history.isLoading || !functionName}
            onClick={() => {
              void history.refresh()
            }}
            variant="outline"
          >
            {history.isLoading ? "Refreshing..." : "Refresh"}
          </Button>
        </div>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        {history.error ? (
          <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {history.error.message}
          </div>
        ) : null}
        {history.runs.length === 0 ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            No function runs loaded.
          </div>
        ) : (
          history.runs.map((run) => (
            <button
              className="rounded-md border border-border bg-muted/30 p-4 text-left text-sm transition-colors hover:bg-muted data-[selected=true]:border-primary"
              data-selected={run.id === history.effectiveSelectedRunId}
              key={run.id}
              onClick={() => {
                history.selectRun(run.id)
                onRunSelect?.(run.id)
              }}
              type="button"
            >
              <div className="flex items-center justify-between gap-3">
                <span className="font-medium">{run.status}</span>
                <span className="text-sm text-muted-foreground">{run.created_at}</span>
              </div>
              <div className="mt-1 truncate text-sm text-muted-foreground">{run.id}</div>
            </button>
          ))
        )}
        {history.nextPageToken ? (
          <Button
            disabled={history.isLoadingMore}
            onClick={() => {
              void history.loadMore()
            }}
            variant="outline"
          >
            {history.isLoadingMore ? "Loading..." : "Load more"}
          </Button>
        ) : null}
      </CardContent>
    </Card>
  )
})
LemmaFunctionRunHistory.displayName = "LemmaFunctionRunHistory"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import {
  Card,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { LemmaFunctionRunHistory } from "@/components/lemma/lemma-function-run-history"
import { LemmaFunctionRunPanel } from "@/components/lemma/lemma-function-run-panel"
import { cn } from "@/lib/utils"

export interface LemmaFunctionSummary {
  name: string
  input_schema?: Record<string, unknown> | null
}

export interface LemmaFunctionRunnerPageProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  functions?: LemmaFunctionSummary[]
  functionName?: string
  onFunctionNameChange?: (functionName: string) => void
  title?: string
  description?: string
  onError?: (error: Error) => void
}

export const LemmaFunctionRunnerPage = React.forwardRef<HTMLDivElement, LemmaFunctionRunnerPageProps>(
  ({
    client,
    podId,
    functions = [],
    functionName,
    onFunctionNameChange,
    title = "Function Runner",
    description = "Choose a function, run it, and inspect recent run history.",
    onError,
    className,
    ...props
  }, ref) => {
  const [internalFunctionName, setInternalFunctionName] = React.useState(functionName ?? functions[0]?.name ?? "")
  const selectedFunctionName = functionName ?? internalFunctionName
  const selectedFunction = functions.find((item) => item.name === selectedFunctionName) ?? null

  React.useEffect(() => {
    if (functionName) return
    setInternalFunctionName((current) => (
      current && functions.some((item) => item.name === current) ? current : (functions[0]?.name ?? "")
    ))
  }, [functionName, functions])

  const setSelectedFunctionName = React.useCallback((nextFunctionName: string) => {
    if (!functionName) setInternalFunctionName(nextFunctionName)
    onFunctionNameChange?.(nextFunctionName)
  }, [functionName, onFunctionNameChange])

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <div className="px-6 pb-6">
          <Select value={selectedFunctionName} onValueChange={setSelectedFunctionName}>
            <SelectTrigger>
              <SelectValue placeholder="Select a function" />
            </SelectTrigger>
            <SelectContent>
              {functions.map((item) => (
                <SelectItem key={item.name} value={item.name}>
                  {item.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </Card>

      {selectedFunctionName ? (
        <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(320px,0.8fr)]">
          <LemmaFunctionRunPanel
            client={client}
            functionName={selectedFunctionName}
            inputSchema={selectedFunction?.input_schema ?? null}
            onError={onError}
            podId={podId}
          />
          <LemmaFunctionRunHistory
            client={client}
            functionName={selectedFunctionName}
            podId={podId}
          />
        </div>
      ) : (
        <Card>
          <CardHeader>
            <CardTitle>No Function Selected</CardTitle>
            <CardDescription>Pass functions or a functionName to render the runner.</CardDescription>
          </CardHeader>
        </Card>
      )}
    </div>
  )
})
LemmaFunctionRunnerPage.displayName = "LemmaFunctionRunnerPage"
